css:
.loader {--loader-bg: #ffffff;
  --loader-secondary-color: #c084fc;
   width: 70px;
   aspect-ratio: 1;
   display: grid;
   color: var(--loader-color, #7c3aed);
   -webkit-mask:radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: l3 1.5s infinite linear;
}
.loader:before, .loader:after  {
  content: "";
   grid-area: 1/1;
   background: radial-gradient(farthest-side at bottom left, currentColor 94%,#0000) top left, radial-gradient(farthest-side at top right , currentColor 94%,#0000) bottom right;
   background-size: 63% 50%;
   background-repeat: no-repeat;
   -webkit-mask: radial-gradient(65% 110% at bottom left, #0000 94%,currentColor) top left, radial-gradient(65% 110% at top right, #0000 94%,currentColor) bottom right;
   -webkit-mask-size: 62% 50%;
   -webkit-mask-repeat: no-repeat;
}
.loader:after  {
  transform: rotate(90deg);
}
@keyframes l3  {
  100%{transform: rotate(1turn)}
}
